const { chromium } = require('playwright');

const url = 'https://jerseycitynj.gov/cityhall/MayorSolomon/mayoralexecutiveorders';
const browser = await chromium.launch({ headless: true });
const page = await browser.newPage();

try {
  await page.goto(url, { waitUntil: 'networkidle', timeout: 30000 });
  const content = await page.content();

  // Extract text and look for executive orders
  const text = content
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  // Look for executive order patterns
  const eoPattern = /Executive\s+Order\s+(?:No\.?\s*)?(\d{4}[-.\s]*\d{1,4})/gi;
  const orders = [];
  let match;

  while ((match = eoPattern.exec(text)) !== null) {
    const num = match[1].replace(/\s+/g, '-');
    const idx = match.index;
    const context = text.slice(Math.max(0, idx - 50), Math.min(text.length, idx + 200)).trim();

    // Check for dates near the match
    const dateMatch = context.match(/(\w+ \d{1,2},? \d{4})|(\d{1,2}\/\d{1,2}\/\d{2,4})/);
    const dateStr = dateMatch ? dateMatch[0] : null;

    // Only include if it looks recent (within last 2 days)
    let isRecent = true;
    if (dateStr) {
      const orderDate = new Date(dateStr);
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 2);
      isRecent = orderDate >= yesterday;
    }

    orders.push({
      ordinance_num: `EO-${num}`,
      title: `Executive Order ${num}`,
      doc_type: 'exec_order',
      source_url: url,
      current_state: 'INTRODUCED',
      full_text: context,
      is_recent: isRecent
    });
  }

  await browser.close();

  // Filter to recent orders only
  const recentOrders = orders.filter(o => o.is_recent);

  if (recentOrders.length === 0) {
    return [{ noNewOrders: true }];
  }

  return recentOrders;
} catch (err) {
  await browser.close();
  console.error('Error fetching exec orders:', err.message);
  return [{ error: err.message }];
}

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient($env.SUPABASE_URL, $env.SUPABASE_SERVICE_KEY);

const items = $input.all().map(i => i.json);
const notifiable = [];

for (const item of items) {
  const slug = item.title.toLowerCase().replace(/[^a-z0-9]/g, '_').slice(0, 40);
  const id = `${item.ordinance_num}_${slug}`;

  const { data: existing } = await supabase.from('ordinances').select('id, current_state').eq('id', id).single();

  if (!existing) {
    await supabase.from('ordinances').insert({ id, ...item });
    notifiable.push({ ...item, id });
  }
}

return notifiable.length ? notifiable : [{ noNew: true }];

const { createClient } = require('@supabase/supabase-js');
const Anthropic = require('@anthropic-ai/sdk');
const { Resend } = require('resend');

const supabase = createClient($env.SUPABASE_URL, $env.SUPABASE_SERVICE_KEY);
const anthropic = new Anthropic.default();
const resend = new Resend($env.RESEND_API_KEY);
const VOTE_BASE = $env.VOTE_BASE_URL || 'https://your-app.vercel.app';

const items = $input.all().map(i => i.json).filter(i => !i.noNew);
if (!items.length) return [{ skipped: true }];

const { data: profiles } = await supabase.from('profiles').select('*').eq('active', true);
if (!profiles?.length) return [{ noProfiles: true }];

const sent = [];

for (const profile of profiles) {
  const analyzed = [];
  for (const item of items) {
    const msg = await anthropic.messages.create({
      model: 'claude-opus-4-20250514',
      max_tokens: 1024,
      messages: [{ role: 'user', content: `Analyze this executive order for a Jersey City resident. Return JSON only.\n\nDOCUMENT: ${item.title}\n${item.full_text || ''}\n\nPROFILE: Ward ${profile.ward}, ${profile.housing}, ${profile.transport}, kids: ${profile.has_kids}, interests: ${(profile.interests||[]).join(', ')}\n\nReturn: {"plain_title":"","what_is_happening":"","personal_impact":"","relevance_score":<1-10>,"current_status":"INTRODUCED","status_context":"","action_available":false}` }]
    });
    try {
      let text = msg.content[0].text.trim();
      const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (fence) text = fence[1].trim();
      const parsed = JSON.parse(text);
      if (parsed.relevance_score >= 5) analyzed.push({ ...parsed, ordinance_id: item.id, doc_type: 'exec_order' });
    } catch {}
  }

  if (analyzed.length) {
    const weekDate = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
    const itemsHtml = analyzed.map(a => `<div style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:20px;margin-bottom:16px;"><span style="background:#f59e0b;color:#fff;font-size:11px;font-weight:600;padding:2px 8px;border-radius:4px;">EXECUTIVE ORDER</span><h3>${a.plain_title}</h3><p>${a.what_is_happening}</p><div style="background:#eff6ff;border-left:3px solid #3b82f6;padding:12px;"><strong>What this means for you:</strong> ${a.personal_impact}</div></div>`).join('');
    const html = `<div style="max-width:600px;margin:0 auto;padding:20px;"><h1>Executive Order Alert</h1><p>Ward ${profile.ward} · ${weekDate}</p>${itemsHtml}</div>`;

    await resend.emails.send({
      from: 'CivicPulse <onboarding@resend.dev>',
      to: [profile.email],
      subject: `\u{1F3D9}\uFE0F JC Alert — ${analyzed[0].plain_title}`,
      html
    });
    sent.push(profile.email);
  }
}

return [{ sent }];
